import unittest
import sys
import os
import json

sys.path.insert(0, os.path.join(os.path.dirname(__file__), '..'))

from app import app


class TestAPIEndpoints(unittest.TestCase):

    def setUp(self):
        self.app = app
        self.app.config['TESTING'] = True
        self.client = self.app.test_client()

    def test_health_endpoint(self):
        response = self.client.get('/health')
        data = json.loads(response.data)

        self.assertEqual(response.status_code, 200)
        self.assertIn('status', data)
        self.assertEqual(data['status'], 'healthy')

    def test_simulation_endpoint_get(self):
        response = self.client.get('/api/simulation')

        self.assertEqual(response.status_code, 405)

    def test_simulation_endpoint_post_basic(self):
        response = self.client.post('/api/simulation',
            data=json.dumps({
                'angle': 45,
                'velocity': 20,
                'gravity': 9.81
            }),
            content_type='application/json'
        )

        self.assertEqual(response.status_code, 200)
        data = json.loads(response.data)

        self.assertIn('trajectory', data)
        self.assertIn('max_height', data)
        self.assertIn('range', data)
        self.assertIn('time_of_flight', data)

    def test_simulation_endpoint_with_language(self):
        response = self.client.post('/api/simulation',
            data=json.dumps({
                'angle': 45,
                'velocity': 20,
                'gravity': 9.81,
                'language': 'en-IN'
            }),
            content_type='application/json'
        )

        self.assertEqual(response.status_code, 200)

    def test_simulation_endpoint_horizontal_launch(self):
        response = self.client.post('/api/simulation',
            data=json.dumps({
                'angle': 0,
                'velocity': 20,
                'gravity': 9.81
            }),
            content_type='application/json'
        )

        self.assertEqual(response.status_code, 200)
        data = json.loads(response.data)
        self.assertEqual(data['max_height'], 0)

    def test_simulation_endpoint_vertical_launch(self):
        response = self.client.post('/api/simulation',
            data=json.dumps({
                'angle': 90,
                'velocity': 20,
                'gravity': 9.81
            }),
            content_type='application/json'
        )

        self.assertEqual(response.status_code, 200)
        data = json.loads(response.data)
        self.assertEqual(data['range'], 0)

    def test_simulate_endpoint_alias(self):
        response = self.client.post('/api/simulate',
            data=json.dumps({
                'angle': 45,
                'velocity': 20,
                'gravity': 9.81
            }),
            content_type='application/json'
        )

        self.assertEqual(response.status_code, 200)

    def test_track_changes_endpoint(self):
        response = self.client.post('/api/track-changes',
            data=json.dumps({
                'session_id': 'test_session',
                'changes': {'angle': 45}
            }),
            content_type='application/json'
        )

        self.assertEqual(response.status_code, 200)
        data = json.loads(response.data)
        self.assertEqual(data['status'], 'tracked')

    def test_track_changes_clear(self):
        response = self.client.post('/api/track-changes',
            data=json.dumps({
                'session_id': 'test_session',
                'action': 'clear'
            }),
            content_type='application/json'
        )

        self.assertEqual(response.status_code, 200)
        data = json.loads(response.data)
        self.assertEqual(data['status'], 'cleared')

    def test_get_changes_endpoint(self):
        response = self.client.get('/api/get-changes?session_id=test_session')

        self.assertEqual(response.status_code, 200)
        data = json.loads(response.data)
        self.assertIn('changes', data)
        self.assertIn('session_id', data)

    def test_combine_chunks_endpoint_no_urls(self):
        response = self.client.post('/api/combine-chunks',
            data=json.dumps({'audio_urls': []}),
            content_type='application/json'
        )

        self.assertEqual(response.status_code, 400)

    def test_media_endpoint_not_found(self):
        response = self.client.get('/media/nonexistent.mp3')

        self.assertEqual(response.status_code, 404)


if __name__ == '__main__':
    unittest.main()

